options.name:
[[[
  let n = entity?.attributes?.friendly_name || entity?.entity_id || 'Zone';
  n = n.replace(/^Comfort\s*/i, '');
  return n.replace(/([a-z])([A-Z])/g, '$1 $2');
]]]

options.icon:
[[[
  const isOff = entity.state === 'off';
  const name = (entity.attributes.friendly_name || '').toLowerCase();
  if (name.includes('light')) return isOff ? 'mdi:lightbulb-off' : 'mdi:lightbulb';
  if (name.includes('door')) return isOff ? 'mdi:door-closed' : 'mdi:door-open';
  if (name.includes('window')) return isOff ? 'mdi:window-closed' : 'mdi:window-open';
  if (name.includes('gate')) return isOff ? 'mdi:gate' : 'mdi:gate-open';
  if (name.includes('pir') || name.includes('motion')) return isOff ? 'mdi:motion-sensor-off' : 'mdi:motion-sensor';
  if (name.includes('tamper')) return isOff ? 'mdi:lock' : 'mdi:lock-open-alert';
  if (name.includes('fire') || name.includes('smoke')) return isOff ? 'mdi:smoke-detector-off' : 'mdi:fire-alert';
  if (name.includes('panic')) return isOff ? 'mdi:alarm-light-off' : 'mdi:alarm-light';
  return isOff ? 'mdi:shield-check' : 'mdi:shield-alert';
]]]

options.state_display:
[[[
  const name = (entity.attributes.friendly_name || '').toLowerCase();
  if (name.includes('light')) return entity.state === 'on' ? 'On' : 'Off';
  if (name.includes('tamper')) return entity.state === 'on' ? 'Tampered' : 'Secure';
  if (name.includes('panic')) return entity.state === 'on' ? 'PANIC' : 'Normal';
  if (name.includes('fire') || name.includes('smoke')) return entity.state === 'on' ? 'ALERT' : 'Normal';
  return entity.state === 'on' ? 'Open' : 'Closed';
]]]

