custom_fields.value:
[[[
  const v = entity?.state;
  if (v === undefined || v === null || v === 'unknown' || v === 'unavailable') {
    return v ?? 'unknown';
  }
  const n = Number(v);
  if (Number.isNaN(n)) {
    return v;
  }
  return String(Math.trunc(n));
]]]

